import Header from '../components/Header';
import Navbar from '../components/Navbar';
import { Container, Typography, Button, Grid, Card, CardContent, CardActions } from '@mui/material';

const HomePage = () => {
    return (
        <div>
            <Header />
            <Navbar />
            <Container maxWidth="lg">
                {/* Hero Section */}
                <Container sx={{ py: 8, textAlign: 'center' }}>
                    <Typography variant="h2" gutterBottom>
                    Welcome to BGP-LLaMA
                    </Typography>
                    <Typography variant="h6" color="textSecondary" paragraph>
                    BGP-LLaMA is an instruction-finetuned, open-source LLM on BGP routing knowledge and analysis
                    </Typography>
                    <Button variant="contained" color="primary">
                    Get Started
                    </Button>
                </Container>

                {/* Cards Section */}
                <Grid container spacing={4} sx={{ pt: 4 }}>
                    {cards.map((card) => (
                    <Grid item key={card.title} xs={12} sm={6} md={4}>
                        <Card>
                        <CardContent>
                            <Typography variant="h5" component="h2">
                            {card.title}
                            </Typography>
                            <Typography>
                            {card.description}
                            </Typography>
                        </CardContent>
                        <CardActions>
                            <Button size="small" color="primary">
                            Learn More
                            </Button>
                        </CardActions>
                        </Card>
                    </Grid>
                    ))}
                </Grid>
            </Container>
        </div>
      );
    };

    // Placeholder data for the cards
    const cards = [
      {
        title: 'Meta Llama 3',
        description: 'Build the future of AI with Meta Llama 3. Llama 3 is an accessible, open-source large language model (LLM) designed for developers, researchers, and businesses.'
      },
      {
        title: 'Another Model',
        description: 'Description of another model or tool provided by Meta Llama.'
      },
      {
        title: 'Yet Another Tool',
        description: 'More information about an additional tool in the Meta Llama suite.'
      }
    ];


export default HomePage;
